import { getBearerToken } from "./bearer";
import { getSessionToken } from "./session";

interface HeadersLike {
  get(name: string): string | null;
}

interface RequestWithAuthSources {
  headers: HeadersLike;
  cookies: {
    get(name: string): { value: string } | undefined;
  };
}

export function getRequestToken(request: RequestWithAuthSources): string | null {
  const bearerToken = getBearerToken(request.headers.get("authorization"));
  if (bearerToken) {
    return bearerToken;
  }

  return getSessionToken(request);
}

import { SignJWT, jwtVerify, type JWTPayload } from "jose";

const textEncoder = new TextEncoder();

function getJwtSecret(): Uint8Array {
  const secret = process.env.JWT_SECRET;
  if (!secret) {
    throw new Error(
      "JWT_SECRET is required. TODO: set a user-managed secret in environment variables.",
    );
  }

  return textEncoder.encode(secret);
}

export async function signAccessToken(
  payload: JWTPayload,
  expiresIn = "1h",
): Promise<string> {
  const secret = getJwtSecret();

  return new SignJWT(payload)
    .setProtectedHeader({ alg: "HS256", typ: "JWT" })
    .setIssuedAt()
    .setExpirationTime(expiresIn)
    .sign(secret);
}

export async function verifyAccessToken(
  token: string,
): Promise<JWTPayload | null> {
  try {
    const secret = getJwtSecret();
    const { payload } = await jwtVerify(token, secret);
    return payload;
  } catch {
    return null;
  }
}

import mysql from "mysql2/promise";
import { drizzle, type MySql2Database } from "drizzle-orm/mysql2";

import { getDatabaseUrl, hasDatabaseUrl } from "./env";
import * as schema from "./schema";

export interface DatabaseHealth {
  status: "up" | "down" | "not_configured";
  message: string;
}

let database: MySql2Database<typeof schema> | null = null;

export function getDb(): MySql2Database<typeof schema> {
  if (database) {
    return database;
  }

  const url = getDatabaseUrl();
  if (!url) {
    throw new Error(
      "DATABASE_URL is required. TODO: provide a user-managed MatrixOne connection string.",
    );
  }

  const pool = mysql.createPool({
    uri: url,
    connectionLimit: 5,
  });

  database = drizzle(pool, { mode: "default", schema });
  return database;
}

export async function checkDatabaseHealth(): Promise<DatabaseHealth> {
  if (!hasDatabaseUrl()) {
    return {
      status: "not_configured",
      message: "DATABASE_URL is not configured",
    };
  }

  const url = getDatabaseUrl();

  let connection: mysql.Connection | undefined;

  try {
    connection = await mysql.createConnection(url);
    await connection.query("SELECT 1");
    return {
      status: "up",
      message: "Database connection healthy",
    };
  } catch (error) {
    const message = error instanceof Error ? error.message : "Unknown error";
    return {
      status: "down",
      message,
    };
  } finally {
    await connection?.end();
  }
}

export function hasDatabaseUrl(): boolean {
  return Boolean(process.env.DATABASE_URL);
}

export function getDatabaseUrl(): string {
  const databaseUrl = process.env.DATABASE_URL;

  if (!databaseUrl) {
    throw new Error(
      "DATABASE_URL is required. TODO: provide a user-managed MatrixOne connection string.",
    );
  }

  return databaseUrl;
}

